233→    override fun onCollectionLoaded(col: Collection) {
234→        super.onCollectionLoaded(col)
235→        if (mNoteEditorBundle != null) {
236→            mAllFieldsNull = false
237→            // loading from the note editor
238→            val toPreview = setCurrentCardFromNoteEditorBundle(col)
239→            if (toPreview != null) {
240→                cardCount = toPreview.note().numberOfCardsEphemeral()
241→                if (cardCount >= 2) {
242→                    previewLayout!!.showNavigationButtons()
243→                }
244→            }
245→        } else {
246→            // loading from the card template editor
247→            mAllFieldsNull = true
248→            // card template with associated card due to opening from note editor
249→            if (mCardList != null && mCardListIndex >= 0 && mCardListIndex < mCardList!!.size) {
250→                currentCard = PreviewerCard(col, mCardList!![mCardListIndex])
251→            } else if (mEditedNotetype != null) { // bare note type (not coming from note editor), or new card template
252→                Timber.d("onCreate() CardTemplatePreviewer started with edited model and template index, displaying blank to preview formatting")
253→                currentCard = getDummyCard(mEditedNotetype!!, mOrdinal)
254→                if (currentCard == null) {
255→                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
256→                    closeCardTemplatePreviewer()
257→                }
258→            }
259→        }
260→        if (currentCard == null) {
261→            showThemedToast(applicationContext, getString(R.string.invalid_template), false)
262→            closeCardTemplatePreviewer()
263→            return
264→        }
265→        displayCardQuestion()
266→        if (mShowingAnswer) {
267→            displayCardAnswer()
268→        }
269→        showBackIcon()
270→    }
