323→    private fun getBundleEditFields(noteEditorBundle: Bundle?): MutableList<String> {
324→        val noteFields = noteEditorBundle!!.getBundle("editFields")
325→            ?: return mutableListOf()
326→        // we map from "int" -> field, but the order isn't guaranteed, and there may be skips.
327→        // so convert this to a list of strings, with null in place of the invalid fields
328→        val elementCount = noteFields.keySet().stream().map { s: String -> s.toInt() }.max { obj: Int, anotherInteger: Int? -> obj.compareTo(anotherInteger!!) }.orElse(-1) + 1
329→        val ret = Array(elementCount) { "" } // init array, nulls cause a crash
330→        for (fieldOrd in noteFields.keySet()) {
331→            ret[fieldOrd.toInt()] = noteFields.getString(fieldOrd)!!
332→        }
333→        return mutableListOf(*ret)
334→    }
