384→     * For cloze note types, the index is the position of the ordinal in the cloze numbers list.
385→     */
386→    private fun ordinalToIndex(col: Collection, ordinal: Int): Int {
387→        if (mEditedNotetype == null) return 0
388→        return if (mEditedNotetype!!.isCloze) {
389→            // Build a note with the fields from the note editor bundle to compute cloze numbers
390→            val fieldValues = getBundleEditFields(mNoteEditorBundle)
