                if (currentCard == null) {
                    showThemedToast(applicationContext, getString(R.string.invalid_template), false)
                    closeCardTemplatePreviewer()
                }
            }
        }
        if (currentCard == null) {
            showThemedToast(applicationContext, getString(R.string.invalid_template), false)
